import{_ as a}from"./chunks/panel-l4-relay-form.DSQdNitK.js";import{_ as e,o as s,c as d,a2 as r}from"./chunks/framework.CuEaBji2.js";const i="/nginx-reverse-emby/screenshots/panel-l4-form-basic.png",l="/nginx-reverse-emby/screenshots/panel-l4-rule.png",P=JSON.parse('{"title":"L4 端口转发","description":"","frontmatter":{},"headers":[],"relativePath":"guides/l4-rules.md","filePath":"guides/l4-rules.md","lastUpdated":1782021666000}'),n={name:"guides/l4-rules.md"};function h(o,t,p,c,b,u){return s(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="l4-端口转发" tabindex="-1">L4 端口转发 <a class="header-anchor" href="#l4-端口转发" aria-label="Permalink to &quot;L4 端口转发&quot;">​</a></h1><p>L4 规则直接转发 TCP 或 UDP 端口流量，不关心协议内容。适合游戏服务器、数据库、非 Web 服务等不需要按域名路由的场景。</p><h2 id="和-http-规则的区别" tabindex="-1">和 HTTP 规则的区别 <a class="header-anchor" href="#和-http-规则的区别" aria-label="Permalink to &quot;和 HTTP 规则的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>HTTP 规则</th><th>L4 规则</th></tr></thead><tbody><tr><td>处理方式</td><td>按域名、路径、HTTP 头</td><td>按 TCP/UDP 端口</td></tr><tr><td>适合</td><td>浏览器访问的 Web 服务</td><td>非 Web 服务的端口转发</td></tr><tr><td>自动 HTTPS</td><td>支持</td><td>不支持，L4 只转发 TCP</td></tr></tbody></table><p>如果只是反代 Emby 或网站，用 <a href="./http-rules">HTTP 规则</a> 更合适。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>控制面已 <a href="./../getting-started/deploy">部署</a> 并正常运行</li><li>面板中能看到 <code>local</code> 节点在线，或已接入远程 Agent</li><li>L4 监听端口已在云防火墙和系统防火墙中放行</li></ul><h2 id="创建-l4-规则" tabindex="-1">创建 L4 规则 <a class="header-anchor" href="#创建-l4-规则" aria-label="Permalink to &quot;创建 L4 规则&quot;">​</a></h2><p>进入 <strong>流量管理 → L4 规则</strong>，选好 Agent 节点，点击 <strong>添加 L4 规则</strong>。</p><h3 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>协议</td><td><code>TCP</code></td><td>选 <code>TCP</code> 或 <code>UDP</code></td></tr><tr><td>监听地址</td><td><code>0.0.0.0</code></td><td>对外监听的地址</td></tr><tr><td>监听端口</td><td><code>18096</code></td><td>客户端连接的端口</td></tr><tr><td>后端地址</td><td><code>origin.example.net:8096</code></td><td>最终要连接的后端服务，可添加多个并排序</td></tr><tr><td>负载均衡</td><td>自适应</td><td>多后端时的调度策略：自适应、轮询、随机</td></tr><tr><td>启用规则</td><td>开</td><td>保存后下发到 Agent</td></tr></tbody></table><p><img src="'+i+'" alt="L4 基础配置"></p><h3 id="协议与监听" tabindex="-1">协议与监听 <a class="header-anchor" href="#协议与监听" aria-label="Permalink to &quot;协议与监听&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>监听模式</td><td>TCP/UDP 转发、SOCKS/HTTP 代理入口，或 WireGuard</td></tr><tr><td>出口 Profile</td><td>出站经过的 Egress Profile</td></tr><tr><td>PROXY Protocol</td><td>TCP 模式下可选接收/发送 PROXY Protocol，透传客户端真实 IP</td></tr></tbody></table><h3 id="relay-配置" tabindex="-1">Relay 配置 <a class="header-anchor" href="#relay-配置" aria-label="Permalink to &quot;Relay 配置&quot;">​</a></h3><p>如果需要流量经过中继节点再到后端，点击 <strong>添加 Relay 层</strong>。新手先配一层一个节点，跑通后再扩展。详见 <a href="./relay">Relay 隧道</a>。</p><p><img src="'+a+`" alt="L4 Relay 配置"></p><h2 id="验证规则" tabindex="-1">验证规则 <a class="header-anchor" href="#验证规则" aria-label="Permalink to &quot;验证规则&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># TCP 端口测试</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">VPS_I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">P</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18096</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果后端是 HTTP 服务，直接浏览器打开</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http://</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;VPS_IP&gt;:18096</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>规则列表里能看到规则卡片即为保存成功。如果卡片带 <code>Relay</code> 标记，说明已关联 Relay 隧道。</p><p><img src="`+l+'" alt="L4 Relay 规则"></p><p>打不开？见 <a href="./../operations/troubleshooting">排障指南</a>。</p>',22)])])}const m=e(n,[["render",h]]);export{P as __pageData,m as default};
